import LinkRenderer from '@kyokuya/react-link'
import type { Link as ILink } from '@yozora/ast'
import { YozoraNodesRenderer } from '@yozora/react-markdown'
import React from 'react'

export function KyokuyaYozoraLink(link: ILink): React.ReactElement {
  const { url, title, children } = link

  return (
    <LinkRenderer url={url} title={title}>
      <YozoraNodesRenderer nodes={children} />
    </LinkRenderer>
  )
}

KyokuyaYozoraLink.displayName = 'KyokuyaYozoraLink'
export default KyokuyaYozoraLink
