import LinkRenderer from '@kyokuya/react-link'
import type { LinkReference as ILinkReference } from '@yozora/ast'
import { YozoraMarkdownContextType, YozoraNodesRenderer } from '@yozora/react-markdown'
import React from 'react'

export function KyokuyaYozoraLinkReference(linkReference: ILinkReference): React.ReactElement {
  const { getDefinition } = React.useContext(YozoraMarkdownContextType)
  const definition = getDefinition(linkReference.identifier)
  const url: string = definition?.url ?? ''
  const title: string | undefined = definition?.title

  return (
    <LinkRenderer url={url} title={title}>
      <YozoraNodesRenderer nodes={linkReference.children} />
    </LinkRenderer>
  )
}

KyokuyaYozoraLinkReference.displayName = 'KyokuyaYozoraLinkReference'
export default KyokuyaYozoraLinkReference
