import { useDeepCompareMemo } from '@guanghechen/react-hooks'
import type { IStorage } from '@kyokuya/react-storage'
import { createLocalStorage, useInitialData } from '@kyokuya/react-storage'
import CircularProgress from '@mui/material/CircularProgress'
import PropTypes from 'prop-types'
import React from 'react'
import usePersistLayoutPostState from '../hook/usePersistLayoutPostState'
import { LayoutPostActionType } from './actions'
import { LayoutPostContextType } from './context'
import reducer from './reducer'
import type { ILayoutPostState } from './state'
import { initLayoutPostState } from './state'
import type { IPostItem } from './types'

export interface PostLayoutContextProviderProps {
  storageKey?: string
  /**
   *
   */
  posts: ReadonlyArray<IPostItem>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

export const PostLayoutContextProvider: React.FC<PostLayoutContextProviderProps> = props => {
  const { storageKey = '@kyokuya/post-layout-post/context', posts: initialPosts, children } = props
  const storage = React.useMemo(
    () => createLocalStorage<Partial<ILayoutPostState>>(storageKey, JSON),
    [storageKey],
  )

  const initialState = useInitialData<Partial<ILayoutPostState>>(storage, { posts: initialPosts })
  if (initialState === null) {
    return <CircularProgress />
  }

  return (
    <PostLayoutContextProviderInner storage={storage} initialState={initialState}>
      {children}
    </PostLayoutContextProviderInner>
  )
}

PostLayoutContextProvider.propTypes = {
  posts: PropTypes.array.isRequired,
  children: PropTypes.node.isRequired,
}

PostLayoutContextProvider.displayName = 'KyokuyaLayoutPostContextProvider'
export default PostLayoutContextProvider

interface IPostLayoutContextProviderInnerProps {
  storage: IStorage<Partial<ILayoutPostState>> | null
  /**
   * Initial context data.
   */
  initialState: Partial<ILayoutPostState>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

const PostLayoutContextProviderInner: React.FC<IPostLayoutContextProviderInnerProps> = props => {
  const { storage, initialState, children } = props
  const { posts: initialPosts = [] } = initialState

  const { tags, posts } = useDeepCompareMemo(() => {
    const tagSet: Set<string> = new Set()
    for (const post of initialPosts) {
      for (const tag of post.tags) tagSet.add(tag)
    }
    const tags: ReadonlyArray<string> = Array.from(tagSet).sort()
    return { tags, posts: initialPosts.slice() }
  }, [initialPosts])

  const [state, dispatch] = React.useReducer(
    reducer,
    { ...initialState, posts, tags },
    initLayoutPostState,
  )

  // save data
  usePersistLayoutPostState(storage, state)

  React.useEffect(() => {
    dispatch({
      type: LayoutPostActionType.REFRESH_STATIC_DATA,
      payload: { tags, posts },
    })
  }, [tags, posts])

  return (
    <LayoutPostContextType.Provider value={{ state, dispatch }}>
      {children}
    </LayoutPostContextType.Provider>
  )
}
