import React from 'react'
import type { ILayoutPostAction } from './actions'
import type { ILayoutPostState } from './state'
import { initLayoutPostState } from './state'

/**
 * Side-effect funcs provided by the LayoutPostContextType.
 */
export interface ILayoutPostContext {
  state: ILayoutPostState
  dispatch: React.Dispatch<ILayoutPostAction>
}

/**
 * Create post layout context.
 */
export const LayoutPostContextType: React.Context<ILayoutPostContext> = React.createContext({
  state: initLayoutPostState(),
  dispatch: (_action: ILayoutPostAction): void => {
    throw new Error(`No available dispatch prepared yet.`)
  },
})
